memberdef.initializer:
(((struct { \
	struct co_array_hdr hdr; \
	union { \
		char vs[MAX(n, sizeof(c))]; \
		union co_val val; \
	} u; \
}){ \
	.hdr = { \
		.capacity = MAX(n, sizeof(c)), \
		.size = sizeof(c) - 1 \
	}, \
	.u = { .vs = c } \
}).u.vs)

(((struct { \
	struct co_array_hdr hdr; \
	union { \
		uint_least8_t os[MAX(n, sizeof(c))]; \
		union co_val val; \
	} u; \
}){ \
	.hdr = { \
		.capacity = MAX(n, sizeof(c)), \
		.size = sizeof(c) - 1 \
	}, \
	.u = { .os = c } \
}).u.os)
